    private void setupActivityResultLaunchers() {
        cameraLauncher = registerForActivityResult(
                new ActivityResultContracts.StartActivityForResult(),
                result -> {
                    if (fileUploadCallback != null) {
                        if (result.getResultCode() == Activity.RESULT_OK && currentPhotoPath != null) {
                            Uri photoUri = Uri.fromFile(new File(currentPhotoPath));
                            fileUploadCallback.onReceiveValue(new Uri[]{photoUri});
                        } else {
                            fileUploadCallback.onReceiveValue(null);
                        }
                        fileUploadCallback = null;
                    }
                }
        );

        fileChooserLauncher = registerForActivityResult(
                new ActivityResultContracts.StartActivityForResult(),
                result -> {
                    if (fileUploadCallback != null) {
                        Uri[] results = null;
                        if (result.getResultCode() == Activity.RESULT_OK && result.getData() != null) {
                            String dataString = result.getData().getDataString();
                            if (dataString != null) {
                                results = new Uri[]{Uri.parse(dataString)};
                            }
                        }
                        fileUploadCallback.onReceiveValue(results);
                        fileUploadCallback = null;
                    }
                }
        );
    }

    @SuppressLint("SetJavaScriptEnabled")
    private void setupWebView() {
        WebSettings webSettings = webView.getSettings();

        // Enable JavaScript
        webSettings.setJavaScriptEnabled(true);
        webSettings.setJavaScriptCanOpenWindowsAutomatically(true);

        // Enable DOM Storage and databases
        webSettings.setDomStorageEnabled(true);
        webSettings.setDatabaseEnabled(true);

        // Enable caching
        webSettings.setCacheMode(WebSettings.LOAD_DEFAULT);
        webSettings.setAppCacheEnabled(true);

        // Enable geolocation
        webSettings.setGeolocationEnabled(true);

        // Enable file access
        webSettings.setAllowFileAccess(true);
        webSettings.setAllowContentAccess(true);

        // Enable mixed content (if needed for development)
        webSettings.setMixedContentMode(WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE);

        // Set user agent to identify hybrid app
        String userAgent = webSettings.getUserAgentString();
        webSettings.setUserAgentString(userAgent + " HybridApp/1.0");

        // Enable responsive design
        webSettings.setUseWideViewPort(true);
        webSettings.setLoadWithOverviewMode(true);

        // Enable zoom
        webSettings.setSupportZoom(true);
        webSettings.setBuiltInZoomControls(true);
        webSettings.setDisplayZoomControls(false);

        // Add JavaScript interface (bridge)
        webView.addJavascriptInterface(new NativeBridge(), "NativeBridge");

        // Set WebViewClient
        webView.setWebViewClient(new HybridWebViewClient());

        // Set WebChromeClient
        webView.setWebChromeClient(new HybridWebChromeClient());
    }

